const fs = require('fs');
const path = require('path');
const { execFileSync } = require('child_process');

const sourceDir = '/home/bajau/pm_source';
const outputDir = '/home/bajau/pm_output';
const workDir   = '/tmp/pm_repack';

function listPmSourceFiles() {
  fs.mkdirSync(sourceDir, { recursive: true });
  return fs.readdirSync(sourceDir, { withFileTypes: true })
    .filter(entry => entry.isFile() && /\.(tar\.gz|tgz|tar\.bz2|tar)$/i.test(entry.name))
    .map(entry => {
      const stat = fs.statSync(path.join(sourceDir, entry.name));
      return { name: entry.name, mtime: stat.mtime };
    })
    .sort((a, b) => (b.mtime - a.mtime) || a.name.localeCompare(b.name));
}

function parsePmFileName(text) {
  const arg = String(text || '')
    .replace(/^\/pm\b/i, '')
    .replace(/\s+--docx\b/ig, '')
    .trim();

  if (!arg) {
    throw new Error(
      'Nama file tidak disertakan.\n' +
      'Format: /pm <nomor atau namafile.tar>\n' +
      'Contoh: /pm 1'
    );
  }

  if (/^\d+$/.test(arg)) {
    const files = listPmSourceFiles();
    const index = Number(arg);
    if (index < 1 || index > files.length) {
      throw new Error(
        'Nomor file tidak tersedia: ' + arg + '\n' +
        'Cek daftar terbaru dengan /list.'
      );
    }
    return files[index - 1].name;
  }

  if (/\s/.test(arg)) {
    throw new Error('Nama file tidak boleh mengandung spasi. Gunakan nomor dari /list atau nama file persis dari /list.');
  }

  const fileName = path.basename(arg);
  if (fileName !== arg || fileName.includes('..') || !/^[A-Za-z0-9._-]+$/.test(fileName)) {
    throw new Error('Nama file tidak valid. Gunakan nomor dari /list atau nama file dari /home/bajau/pm_source/.');
  }

  if (!/\.(tar\.gz|tgz|tar\.bz2|tar)$/i.test(fileName)) {
    throw new Error('Format file tidak valid. Ekstensi yang didukung: .tar, .tar.gz, .tgz, .tar.bz2');
  }

  return fileName;
}

function walkFiles(dir) {
  const result = [];
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const fullPath = path.join(dir, entry.name);
    if (entry.isDirectory()) result.push(...walkFiles(fullPath));
    else if (entry.isFile()) result.push(fullPath);
  }
  return result;
}

const fileName = parsePmFileName($json.text || '');

fs.mkdirSync(sourceDir, { recursive: true });
fs.mkdirSync(outputDir, { recursive: true });

const sourcePath = path.join(sourceDir, fileName);
const baseName   = fileName.replace(/\.(tar\.gz|tgz|tar\.bz2|tar)$/i, '');
const outputName = baseName + '_compressed_' + Date.now() + '.tar.gz';
const outputPath = path.join(outputDir, outputName);

if (!fs.existsSync(sourcePath)) {
  throw new Error(
    'File tidak ditemukan: ' + sourcePath + '\n' +
    'Upload file via Termius/SCP ke direktori:\n' +
    sourceDir + '/'
  );
}

const sizeBefore   = fs.statSync(sourcePath).size;
const sizeMBBefore = (sizeBefore / 1024 / 1024).toFixed(1);
const allowedExt   = new Set(['.txt', '.log', '.conf', '.json', '.csv', '.out', '.sh', '.cnf']);

try {
  fs.rmSync(workDir, { recursive: true, force: true });
  fs.mkdirSync(workDir, { recursive: true });

  execFileSync('tar', ['-xf', sourcePath, '-C', workDir], { timeout: 120000 });

  for (const filePath of walkFiles(workDir)) {
    const ext  = path.extname(filePath).toLowerCase();
    const base = path.basename(filePath).toLowerCase();
    if (!allowedExt.has(ext) && base !== 'mariadb.conf') {
      fs.rmSync(filePath, { force: true });
    }
  }

  execFileSync('tar', ['-czf', outputPath, '-C', workDir, '.'], { timeout: 120000 });
} finally {
  fs.rmSync(workDir, { recursive: true, force: true });
}

const sizeAfter   = fs.statSync(outputPath).size;
const sizeMBAfter = (sizeAfter / 1024 / 1024).toFixed(1);

return [{ json: {
  chat_id      : $json.chat_id,
  source_file  : sourcePath,
  output_file  : outputPath,
  file_name    : outputName,
  original_mb  : sizeMBBefore,
  compressed_mb: sizeMBAfter
} }];

const { execSync } = require('child_process');
const fs = require('fs');

const outputFile   = $json.output_file;
const chatId       = $json.chat_id;
const fileName     = $json.file_name;
const originalMB   = $json.original_mb;
const compressedMB = $json.compressed_mb;

if (!fs.existsSync(outputFile)) {
  throw new Error(`File hasil compress tidak ditemukan: ${outputFile}`);
}

execSync(`mkdir -p /tmp/pm_work && cp "${outputFile}" /tmp/pm_work/upload.tar.gz`, { shell: '/bin/sh' });
execSync(`rm -f "${outputFile}"`, { shell: '/bin/sh' });

return [{ json: {
  chat_id      : chatId,
  file_name    : fileName,
  download_ok  : true,
  original_mb  : originalMB,
  compressed_mb: compressedMB
} }];

const { execSync } = require('child_process');

const TARGET_FILES = [
  'hostname.txt',
  'os_info.txt',
  'os-release.txt',
  'etc_os_release.txt',
  'uname.txt',
  'kernel.txt',
  'uptime.txt',
  'loadavg.txt',
  'lscpu.txt',
  'cpuinfo.txt',
  'free.txt',
  'free_m.txt',
  'memory.txt',
  'meminfo.txt',
  'df.txt',
  'df_h.txt',
  'disk.txt',
  'lsblk.txt',
  'mount.txt',
  'ip_addr.txt',
  'ip_address.txt',
  'ifconfig.txt',
  'network.txt',
  'route.txt',
  'mariadb_version.txt',
  'mariadb_glob_vars.txt',
  'mariadb_engine_stats.txt',
  'table_engine.txt',
  'db_size.txt',
  'mysql_tunner.txt',
  'mysql_tuner.txt',
  'pt_summary.txt',
  'pt_mysql_summary.txt',
  'cluster_integrity.txt',
  'slave_status.txt',
  'gtid.txt',
  'sar.txt',
  'sar_cpu.txt',
  'sar_memory.txt',
  'sar_disk.txt',
  'sar_network.txt',
  'backup_status.txt',
  'backup.txt',
  'sosreport_warn.txt',
];

const LINE_LIMITS = {
  'sar.txt'                 : 6000,
  'sar_cpu.txt'             : 3000,
  'sar_memory.txt'          : 3000,
  'sar_disk.txt'            : 2000,
  'sar_network.txt'         : 2000,
  'mariadb_glob_vars.txt'   : 900,
  'mariadb_engine_stats.txt': 550,
  'table_engine.txt'        : 700,
  'db_size.txt'             : 350,
  'mysql_tunner.txt'        : 600,
  'mysql_tuner.txt'         : 600,
  'pt_summary.txt'          : 900,
  'pt_mysql_summary.txt'    : 1000,
  'slave_status.txt'        : 450,
  'gtid.txt'                : 300,
  'cluster_integrity.txt'   : 350,
  'sosreport_warn.txt'      : 120,
};
const DEFAULT_LINES = 260;
const FOCUS_FILE_RE = /(hostname|os[-_]?release|uname|kernel|uptime|loadavg|lscpu|cpuinfo|meminfo|free|memory|df|disk|lsblk|mount|ip[-_]?addr|ip[-_]?address|ifconfig|network|route|sar|mariadb|mysql|table_engine|db_size|tunner|tuner|pt[-_]?summary|pt[-_]?mysql|cluster|wsrep|slave|replica|gtid|backup|sosreport)/i;
const EXCLUDE_FILE_RE = /(private[_-]?key|id_rsa|\.pem$|\.key$|password|passwd|secret|shadow|authorized_keys|known_hosts)/i;

function shQuote(value) {
  return "'" + String(value).replace(/'/g, "'\\''") + "'";
}

function run(cmd, options = {}) {
  return execSync(cmd, { shell: '/bin/sh', maxBuffer: 20 * 1024 * 1024, ...options }).toString();
}

function safeLabel(value) {
  return String(value || '')
    .replace(/^\.\/+/, '')
    .replace(/[\\\/]+/g, '__')
    .replace(/[^A-Za-z0-9._-]+/g, '_')
    .replace(/^_+|_+$/g, '') || 'unknown';
}

function limitFor(label) {
  const base = String(label || '').split(/[\\\/]/).pop();
  return LINE_LIMITS[base] || LINE_LIMITS[label] || DEFAULT_LINES;
}

let stdout = '', stderr = '';
try {
  execSync([
    'rm -rf /tmp/pm_extracted/* /tmp/pm_extracted/.[!.]* 2>/dev/null || true',
    '&& mkdir -p /tmp/pm_extracted',
    '&& (tar -xzf /tmp/pm_work/upload.tar.gz -C /tmp/pm_extracted 2>/dev/null',
    '   || tar -xf  /tmp/pm_work/upload.tar.gz -C /tmp/pm_extracted 2>/dev/null',
    '   || tar -xjf /tmp/pm_work/upload.tar.gz -C /tmp/pm_extracted 2>/dev/null)',
  ].join(' '), { shell: '/bin/sh', timeout: 60000, maxBuffer: 20 * 1024 * 1024 });

  const allFiles = run('cd /tmp/pm_extracted && find . -type f 2>/dev/null | sed "s#^./##" | sort');
  const allPaths = allFiles
    .split('\n')
    .map((line) => line.trim())
    .filter(Boolean)
    .map((rel) => ({ rel, abs: '/tmp/pm_extracted/' + rel }));

  let fileContents = '';
  const seen = new Set();

  function appendFile(absPath, label, forcedLimit) {
    if (!absPath || seen.has(absPath)) return;
    const safe = safeLabel(label);
    if (EXCLUDE_FILE_RE.test(safe)) return;
    const limit = forcedLimit || limitFor(label);
    let content = '';
    try {
      const readCmd = /sar/i.test(String(label || '')) ? 'tail -n ' : 'head -n ';
      content = run(readCmd + Number(limit || DEFAULT_LINES) + ' ' + shQuote(absPath) + ' 2>/dev/null');
    } catch (e) {
      content = '';
    }
    if (!content.trim()) return;
    seen.add(absPath);
    fileContents += '\n==BEGIN_FILE:' + safe + '==\n' + content + '\n==END_FILE:' + safe + '==\n';
  }

  for (const target of TARGET_FILES) {
    const found = run('find /tmp/pm_extracted -type f -name ' + shQuote(target) + ' 2>/dev/null | sort | head -1').trim();
    if (found) appendFile(found, target, limitFor(target));
  }

  const cnfFiles = run('find /tmp/pm_extracted -type f \\( -name "*.cnf" -o -name "*.conf" -o -name "my.cnf" -o -name "mariadb.conf" \\) 2>/dev/null | sort')
    .trim()
    .split('\n')
    .filter(Boolean);

  for (const cnf of cnfFiles) {
    let label = cnf.split('/').pop();
    try {
      const rel = run('cd /tmp/pm_extracted && realpath --relative-to=/tmp/pm_extracted ' + shQuote(cnf)).trim();
      if (rel) label = rel;
    } catch (e) {}
    appendFile(cnf, label, 220);
  }

  for (const file of allPaths) {
    if (seen.has(file.abs)) continue;
    if (EXCLUDE_FILE_RE.test(file.rel)) continue;
    if (!FOCUS_FILE_RE.test(file.rel)) continue;
    appendFile(file.abs, file.rel, limitFor(file.rel));
  }

  stdout = '=EXTRACT_OK=\n=FILELIST=\n' + allFiles + '\n=FOCUS_FILTER=\n' +
    'Filtered for PM report needs: OS information, network identity, CPU, memory, disk/partition, SAR performance with latest 30-day focus, MariaDB status, table/database size, backup, master-replica, Galera/WSREP, GTID, and PM script evidence.\n' +
    '=CONTENTS=\n' + fileContents;
} catch (err) {
  stdout = err.stdout ? err.stdout.toString() : '';
  stderr = err.message;
}

return [{ json: { stdout, stderr, target_files: TARGET_FILES, focus_filter: 'pm-report-template-v2' } }];

const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const meta   = $('Load Compressed File').first().json;

const REQUIRED_PM_FILES = [
  'mariadb_version.txt',
  'mariadb_glob_vars.txt',
  'mariadb_engine_stats.txt',
  'table_engine.txt',
  'db_size.txt',
  'mysql_tunner.txt',
  'pt_summary.txt',
  'pt_mysql_summary.txt',
  'cluster_integrity.txt',
  'slave_status.txt',
  'gtid.txt',
  'sar.txt',
];
const OPTIONAL_PM_FILES = ['sosreport_warn.txt', 'backup_status.txt', 'backup.txt'];

const extractOk     = stdout.includes('=EXTRACT_OK=');
const fileListMatch = stdout.match(/=FILELIST=([\s\S]*?)=FOCUS_FILTER=/) || stdout.match(/=FILELIST=([\s\S]*?)=CONTENTS=/);
const fileList      = fileListMatch ? fileListMatch[1].trim() : 'Tidak ditemukan';
const contentSec    = stdout.split('=CONTENTS=')[1] || '';

const sections = {};
for (const m of contentSec.matchAll(/==BEGIN_FILE:([^=\n]+)==\n?([\s\S]*?)\n?==END_FILE:[^=\n]+==/g)) {
  sections[m[1].trim()] = m[2].trim();
}

function clean(value, maxLen) {
  const text = String(value ?? '')
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
    .replace(/\r/g, '')
    .replace(/\t/g, '    ')
    .trim();
  return maxLen && text.length > maxLen ? text.slice(0, maxLen) + '\n...[truncated]...' : text;
}

function parseKv(text) {
  const out = {};
  for (const line of String(text || '').split('\n')) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    let match = trimmed.match(/^([A-Za-z0-9_.$-]+)\s*[:=]\s*(.+)$/);
    if (!match) {
      const parts = trimmed.split(/\s+/);
      if (parts.length >= 2 && /^[A-Za-z0-9_.$-]+$/.test(parts[0])) match = [trimmed, parts[0], parts.slice(1).join(' ')];
    }
    if (match) out[match[1]] = match[2];
  }
  return out;
}

function parseSlave(text) {
  const out = {};
  for (const line of String(text || '').split('\n')) {
    const match = line.match(/^\s*([A-Za-z0-9_]+):\s*(.*)$/);
    if (match) out[match[1]] = match[2].trim();
  }
  return out;
}

function asInt(value, fallback) {
  const n = Number(String(value ?? '').replace(/[^0-9.-]/g, ''));
  return Number.isFinite(n) ? n : fallback;
}

function secondsHuman(value) {
  const n = asInt(value, NaN);
  if (!Number.isFinite(n)) return value || 'N/A';
  const days = Math.floor(n / 86400);
  const hours = Math.floor((n % 86400) / 3600);
  const minutes = Math.floor((n % 3600) / 60);
  return days + ' days, ' + hours + ' hours, ' + minutes + ' minutes';
}

function allText(matchRe) {
  return Object.entries(sections)
    .filter(([key]) => matchRe.test(key))
    .map(([key, value]) => '--- ' + key + ' ---\n' + value)
    .join('\n\n');
}

function firstMatch(text, patterns, fallback = 'N/A') {
  for (const re of patterns) {
    const match = String(text || '').match(re);
    if (match) return clean(match[1] || match[2] || match[0], 300).replace(/^["']|["']$/g, '');
  }
  return fallback;
}

function firstIp(text) {
  const matches = String(text || '').match(/\b(?:\d{1,3}\.){3}\d{1,3}\b/g) || [];
  return matches.find((ip) => !/^(127|0|255)\./.test(ip) && ip !== '255.255.255.255') || 'N/A';
}

function firstMac(text) {
  const match = String(text || '').match(/\b[0-9A-Fa-f]{2}(?::[0-9A-Fa-f]{2}){5}\b/);
  return match ? match[0] : 'N/A';
}

function parseDiskRows(text) {
  const rows = [];
  for (const line of String(text || '').split('\n')) {
    const trimmed = line.trim();
    if (!/\s\d{1,3}%\s/.test(' ' + trimmed + ' ')) continue;
    const parts = trimmed.split(/\s+/);
    const pctIdx = parts.findIndex((part) => /^\d{1,3}%$/.test(part));
    if (pctIdx < 4) continue;
    rows.push({
      filesystem: parts.slice(0, pctIdx - 3).join(' ') || parts[0],
      size: parts[pctIdx - 3] || 'N/A',
      used: parts[pctIdx - 2] || 'N/A',
      free: parts[pctIdx - 1] || 'N/A',
      pct: parts[pctIdx] || 'N/A',
      mount: parts.slice(pctIdx + 1).join(' ') || 'N/A'
    });
  }
  return rows.slice(0, 20);
}

function parseDateRange(text) {
  const matches = String(text || '').match(/\b\d{4}-\d{2}-\d{2}\b|\b\d{2}\/\d{2}\/\d{2,4}\b|\b\d{2}-\d{2}-\d{2,4}\b/g) || [];
  const uniq = [...new Set(matches)];
  if (!uniq.length) return 'N/A';
  return uniq[0] + (uniq.length > 1 ? ' - ' + uniq[uniq.length - 1] : '');
}

const globVars = parseKv(sections['mariadb_glob_vars.txt']);
const cnfKeys = Object.keys(sections).filter((key) => key.endsWith('.cnf') || key.endsWith('.conf') || key === 'mariadb.conf' || key === 'my.cnf').sort();
const cnfKv = parseKv(cnfKeys.map((key) => sections[key]).join('\n'));
const slaveKv = parseSlave(sections['slave_status.txt']);
const clusterKv = parseKv(sections['cluster_integrity.txt']);
const gtidKv = parseKv(sections['gtid.txt']);
const osText = allText(/hostname|os|release|uname|kernel|uptime|load|lscpu|cpuinfo|free|memory|meminfo|df|disk|lsblk|mount|ip|ifconfig|network|route|pt_summary/i);
const sarText = allText(/sar/i);
const backupText = allText(/backup/i);

const bpReads = asInt(globVars.Innodb_buffer_pool_reads, 0);
const bpRequests = asInt(globVars.Innodb_buffer_pool_read_requests, 1) || 1;
const bpRatio = Number(((bpRequests / (bpReads + bpRequests)) * 100).toFixed(2));
const maxConn = asInt(cnfKv.max_connections || globVars.max_connections, 151) || 151;
const threadsConn = asInt(globVars.Threads_connected, 0);
const connPct = Number(((threadsConn / Math.max(maxConn, 1)) * 100).toFixed(1));
const slowQueries = asInt(globVars.Slow_queries, 0);
const rowLockWaits = asInt(globVars.Innodb_row_lock_waits, 0);

const diskRows = parseDiskRows(osText);
const diskOver80 = diskRows.filter((row) => asInt(row.pct, 0) >= 80);
const mariadbVersion = clean(sections['mariadb_version.txt'] || 'N/A', 300).split('\n')[0] || 'N/A';
const replicationHealth = slaveKv.Slave_IO_Running || slaveKv.Slave_SQL_Running
  ? ((slaveKv.Slave_IO_Running === 'Yes' && slaveKv.Slave_SQL_Running === 'Yes') ? 'Synced' : 'Not Synced')
  : 'N/A';
const galeraStatus = clusterKv.wsrep_cluster_status || clusterKv.wsrep_local_state_comment || 'N/A';

let overall = 'HEALTHY';
if (slowQueries > 100000 || rowLockWaits > 0 || bpRatio < 99 || connPct >= 80 || diskOver80.length) overall = 'WARNING';
if (bpRatio < 90 || connPct >= 95 || diskOver80.some((row) => asInt(row.pct, 0) >= 95)) overall = 'CRITICAL';

const presentFiles = [...REQUIRED_PM_FILES, ...OPTIONAL_PM_FILES].filter((file) => sections[file]);
const missingFiles = REQUIRED_PM_FILES.filter((file) => !sections[file]);

const focusedFacts = {
  sourceArchive: meta.file_name,
  collectionProfile: 'Script GENERATE PM MARIADB V2.0',
  overallStatus: overall,
  reportPeriod: parseDateRange(sarText),
  serverInformation: {
    hostname: firstMatch(osText, [/hostname\s*[:=]\s*([^\n]+)/i, /Host(?:name)?\s*[:=]\s*([^\n]+)/i], String(meta.file_name || '').split('_')[0] || 'SERVER'),
    ipAddress: firstIp(osText),
    macAddress: firstMac(osText),
    operatingSystem: firstMatch(osText, [/PRETTY_NAME=["']?([^"'\n]+)/i, /Operating System\s*[:=]\s*([^\n]+)/i, /OS\s*[:=]\s*([^\n]+)/i]),
    kernel: firstMatch(osText, [/kernel(?: release)?\s*[:=]\s*([^\n]+)/i, /Linux\s+\S+\s+([0-9][^\s]+)/i]),
    processor: firstMatch(osText, [/model name\s*[:=]\s*([^\n]+)/i, /CPU\(s\)\s*[:=]\s*([^\n]+)/i, /Processor\s*[:=]\s*([^\n]+)/i]),
    memory: firstMatch(osText, [/Mem(?:ory)?Total\s*[:=]\s*([^\n]+)/i, /^Mem:\s*([^\n]+)/mi, /Memory\s*[:=]\s*([^\n]+)/i]),
    uptime: firstMatch(osText, [/uptime\s*[:=]\s*([^\n]+)/i, /(up\s+[^,\n]+,\s+\d+\s+users?)/i], secondsHuman(globVars.Uptime)),
    loadAverage: firstMatch(osText, [/load average[s]?:\s*([0-9.,\s]+)/i, /loadavg\s*[:=]\s*([^\n]+)/i]),
    diskRows,
  },
  databaseCheck: {
    mariadbVersion,
    uptime: secondsHuman(globVars.Uptime),
    runningPort: cnfKv.port || globVars.port || 'N/A',
    datadir: cnfKv.datadir || globVars.datadir || 'N/A',
    maxConnections: maxConn,
    threadsConnected: threadsConn,
    threadsRunning: asInt(globVars.Threads_running, 0),
    connectionUsagePct: connPct,
    slowQueries,
    longQueryTime: cnfKv.long_query_time || globVars.long_query_time || 'N/A',
    bufferPoolHitRatioPct: bpRatio,
    rowLockWaits,
    questions: globVars.Questions || globVars.Queries || 'N/A',
  },
  replicationAndCluster: {
    replicationHealth,
    slaveIoRunning: slaveKv.Slave_IO_Running || 'N/A',
    slaveSqlRunning: slaveKv.Slave_SQL_Running || 'N/A',
    secondsBehindMaster: slaveKv.Seconds_Behind_Master || 'N/A',
    gtidCurrentPos: gtidKv.gtid_current_pos || 'N/A',
    gtidBinlogPos: gtidKv.gtid_binlog_pos || 'N/A',
    wsrepClusterSize: clusterKv.wsrep_cluster_size || 'N/A',
    wsrepClusterStatus: clusterKv.wsrep_cluster_status || 'N/A',
    wsrepLocalState: clusterKv.wsrep_local_state_comment || 'N/A',
    galeraStatus,
  },
  performance: {
    sarPeriod: parseDateRange(sarText),
    sarEvidence: clean(sarText.split('\n').filter((line) => /Average|all|CPU|mem|DEV|IFACE|totsck|rtps|wtps/i.test(line)).slice(-80).join('\n') || 'N/A', 9000),
    diskOver80,
  },
  backup: {
    evidence: backupText ? clean(backupText, 3000) : 'N/A',
  },
  dataCoverage: {
    presentFiles,
    missingFiles,
    configFiles: cnfKeys,
  }
};

const evidenceKeys = [
  'mariadb_version.txt',
  'mariadb_glob_vars.txt',
  'cluster_integrity.txt',
  'slave_status.txt',
  'gtid.txt',
  'db_size.txt',
  'table_engine.txt',
  'mysql_tunner.txt',
  'pt_summary.txt',
  'pt_mysql_summary.txt',
  'sar.txt',
  'backup_status.txt',
  'backup.txt',
];
const evidence = evidenceKeys
  .filter((key) => sections[key])
  .map((key) => '--- ' + key + ' ---\n' + clean(sections[key], 3500))
  .join('\n\n');

const prompt = extractOk
  ? [
      'Kamu adalah senior DBA dan system engineer untuk Preventive Maintenance MariaDB/PerconaDB di lingkungan Linux.',
      '',
