function byIndex(nodeName, index) {
  try {
    const values = $items(nodeName, 0, 0) || [];
    return (values[index] && values[index].json) || {};
  } catch (err) {
    try {
      const values = $items(nodeName) || [];
      return (values[index] && values[index].json) || {};
    } catch (innerErr) {
      return {};
    }
  }
}

function firstNonEmpty(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') return String(value).trim();
  }
  return 'N/A';
}

function asNumber(value) {
  const n = Number(String(value ?? '').replace(/[^0-9.-]/g, ''));
  return Number.isFinite(n) ? n : NaN;
}

function formatPct(value) {
  const n = asNumber(value);
  if (!Number.isFinite(n)) return 'N/A';
  return (Math.round(n * 10) / 10).toString().replace(/\.0$/, '') + '%';
}

function statusText(ok, okText, badText, unknownText) {
  if (ok === true) return okText;
  if (ok === false) return badText;
  return unknownText;
}

function sourceStatus(condition, sourceName) {
  return condition ? 'Tersedia di file ' + sourceName + '.' : 'N/A (File sumber: ' + sourceName + ')';
}

