function ensureTemplateDocx() {
  const candidates = [
    env.PM_DOCX_TEMPLATE_PATH,
    '/home/bajau/pm_template/format_document_pm.docx',
    '/home/bajau/pm_template/Copy of format document PM.docx',
    '/data/pm_template/format_document_pm.docx',
    '/tmp/pm_format_template.docx'
  ].filter(Boolean);

  for (const candidate of candidates) {
    try {
      if (fs.existsSync(candidate) && fs.statSync(candidate).size > 0) return candidate;
    } catch (e) {}
  }

  const fallback = '/tmp/pm_format_template.docx';
  fs.writeFileSync(fallback, Buffer.from(EMBEDDED_TEMPLATE_B64, 'base64'));
  return fallback;
}

