_EN[dt.month - 1] + ' ' + str(dt.year)\n    month_year = MONTHS_EN[dt.month - 1] + ' ' + str(dt.year)\nexcept Exception:\n    today_fmt = today\n    month_year = today\n\nos.makedirs(output_dir, exist_ok=True)\n\nBRAND_BLUE = '1F4E79'\nDARK_BLUE = '17365D'\nLIGHT_GRAY = 'F2F2F2'\nMID_GRAY = 'D9D9D9'\nWHITE = 'FFFFFF'\nGREEN = '70AD47'\nYELLOW = 'FFC000'\nORANGE = 'F4B183'\nRED = 'C00000'\nBLACK = '000000'\n\ndef hex_to_rgb(hex_str):\n    h = (hex_str or BLACK).replace('#', '')\n    if len(h) != 6:\n        h = BLACK\n    return RGBColor(int(h[0:2], 16), int(h[2:4], 16), int(h[4:6], 16))\n\ndef safe_int(value, default=0):\n    try:\n        s = str(value).strip()\n        if s.lower() in ('', 'none', 'null', 'n/a', '-'):\n            return default\n        return int(float(s.replace(',', '')))\n    except Exception:\n        return default\n\ndef safe_float(value, default=0.0):\n    try:\n        s = str(value).strip()\n        if s.lower() in ('', 'none', 'null', 'n/a', '-'):\n            return default\n        return float(s.replace(',', ''))\n    except Exception:\n        return default\n\ndef first_nonempty_line(text, default='N/A'):\n    for line in str(text or '').split('\\\\n'):\n        if line.strip() and not line.strip().startswith('---'):\n            return line.strip()\n    return default\n\ndef parse_kv(text):\n    result = {}\n    for line in (text or '').split('\\\\n'):\n        raw = line.strip()\n        if not raw or raw.startswith('#') or raw.startswith('---'):\n            continue\n        if ':' in raw and not raw.startswith('http'):\n            key, val = raw.split(':', 1)\n        elif '=' in raw:\n            key, val = raw.split('=', 1)\n        else:\n            parts = raw.split()\n            if len(parts) < 2:\n                continue\n            key, val = parts[0], ' '.join(parts[1:])\n        key = key.strip()\n        val = val.strip().strip('\"').strip(\"'\")\n        if key:\n            result[key] = val\n    return result\n\ndef size_to_gb(value):\n    m = re.search(r'([0-9]+(?:\\\\.[0-9]+)?)\\\\s*([KMGTPE]?B?|[KMGTPE])?$', str(value or '').strip(), re.I)\n    if not m:\n        return 0.0\n    num = safe_float(m.group(1), 0.0)\n    unit = (m.group(2) or 'G').upper().replace('B', '')\n    factor = {'K': 1/(1024*1024), 'M': 1/1024, 'G': 1, 'T': 1024, 'P': 1024*1024, 'E': 1024*1024*1024, '': 1}.get(unit, 1)\n    return num * factor\n\ndef bar_chart(val, max_val, width=18):\n    try:\n        val = float(val or 0)\n        max_val = float(max_val or 1)\n        ratio = min(max(val, 0) / max(max_val, 1), 1)\n        filled = round(ratio * width)\n        return '[' + ('#' * filled) + ('.' * (width - filled)) + '] ' + str(round(val, 2))\n    except Exception:\n        return '-'\n\ndef severity_cell(severity):\n    sev = str(severity or '').upper()\n    if sev == 'CRITICAL':\n        return {'text': 'CRITICAL', 'fill': RED, 'color': WHITE, 'bold': True, 'align': 'center'}\n    if sev == 'HIGH':\n        return {'text': 'HIGH', 'fill': ORANGE, 'color': BLACK, 'bold': True, 'align': 'center'}\n    if sev == 'MEDIUM':\n        return {'text': 'MEDIUM', 'fill': YELLOW, 'color': BLACK, 'bold': True, 'align': 'center'}\n    if sev == 'LOW':\n        return {'text': 'LOW', 'fill': MID_GRAY, 'color': BLACK, 'bold': True, 'align': 'center'}\n    return {'text': sev or '-', 'fill': LIGHT_GRAY, 'color': BLACK, 'bold': True, 'align': 'center'}\n\ndef status_cell(text, ok=None):\n    label = str(text or '-')\n    if ok is True:\n        fill, color = GREEN, WHITE\n    elif ok is False:\n        fill, color = RED, WHITE\n    else:\n        fill, color = MID_GRAY, BLACK\n    return {'text': label, 'fill': fill, 'color': color, 'bold': True, 'align': 'center'}\n\ndef set_cell_bg(cell, hex_color):\n    tcPr = cell._tc.get_or_add_tcPr()\n    shd = tcPr.find(qn('w:shd'))\n    if shd is None:\n        shd = OxmlElement('w:shd')\n        tcPr.append(shd)\n    shd.set(qn('w:val'), 'clear')\n    shd.set(qn('w:color'), 'auto')\n    shd.set(qn('w:fill'), hex_color or WHITE)\n\ndef set_cell_border(cell, color='A6A6A6', size='4'):\n    tcPr = cell._tc.get_or_add_tcPr()\n    tcBorders = tcPr.find(qn('w:tcBorders'))\n    if tcBorders is None:\n        tcBorders = OxmlElement('w:tcBorders')\n        tcPr.append(tcBorders)\n    for edge in ('top', 'left', 'bottom', 'right', 'insideH', 'insideV'):\n        tag = qn('w:' + edge)\n        element = tcBorders.find(tag)\n        if element is None:\n            element = OxmlElement('w:' + edge)\n            tcBorders.append(element)\n        element.set(qn('w:val'), 'single')\n        element.set(qn('w:sz'), size)\n        element.set(qn('w:space'), '0')\n        element.set(qn('w:color'), color)\n\ndef set_cell_text(cell, value, bold=False, color=BLACK, size=9, align=None, mono=False):\n    cell.text = ''\n    p = cell.paragraphs[0]\n    if align == 'center':\n        p.alignment = WD_ALIGN_PARAGRAPH.CENTER\n    elif align == 'right':\n        p.alignment = WD_ALIGN_PARAGRAPH.RIGHT\n    else:\n        p.alignment = WD_ALIGN_PARAGRAPH.LEFT\n    run = p.add_run(str(value if value is not None else '-'))\n    run.bold = bold\n    run.font.size = Pt(size)\n    run.font.color.rgb = hex_to_rgb(color)\n    if mono:\n        run.font.name = 'Courier New'\n        run._element.rPr.rFonts.set(qn('w:eastAsia'), 'Courier New')\n    cell.vertical_alignment = WD_CELL_VERTICAL_ALIGNMENT.CENTER\n\ndef style_table(table):\n    table.alignment = WD_TABLE_ALIGNMENT.CENTER\n    table.autofit = True\n    for row in table.rows:\n        for cell in row.cells:\n            set_cell_border(cell)\n            for p in cell.paragraphs:\n                p.paragraph_format.space_after = Pt(0)\n\ndef add_table(doc, headers, rows, header_fill=BRAND_BLUE):\n    headers = list(headers)\n    table = doc.add_table(rows=1, cols=len(headers))\n    style_table(table)\n    for i, header in enumerate(headers):\n        cell = table.rows[0].cells[i]\n        set_cell_bg(cell, header_fill)\n        set_cell_text(cell, header, bold=True, color=WHITE, size=8.5, align='center')\n    for ri, row in enumerate(rows or []):\n        values = list(row)\n        if len(values) < len(headers):\n            values += [''] * (len(headers) - len(values))\n        cells = table.add_row().cells\n        for ci in range(len(headers)):\n            value = values[ci]\n            fill = WHITE if ri % 2 else 'F7F9FB'\n            if isinstance(value, dict):\n                fill = value.get('fill', fill)\n                set_cell_bg(cells[ci], fill)\n                set_cell_text(\n                    cells[ci], value.get('text', '-'),\n                    bold=value.get('bold', False),\n                    color=value.get('color', BLACK),\n                    size=value.get('size', 8.5),\n                    align=value.get('align'),\n                    mono=value.get('mono', False),\n                )\n            else:\n                set_cell_bg(cells[ci], fill)\n                set_cell_text(cells[ci], value, size=8.5)\n    doc.add_paragraph()\n    return table\n\ndef add_para(doc, text='', bold=False, italic=False, mono=False, color=BLACK, size=10, align=None, style=None):\n    try:\n        p = doc.add_paragraph(style=style) if style else doc.add_paragraph()\n    except Exception:\n        p = doc.add_paragraph()\n    p.paragraph_format.space_after = Pt(4)\n    if align == 'center':\n        p.alignment = WD_ALIGN_PARAGRAPH.CENTER\n    elif align == 'right':\n        p.alignment = WD_ALIGN_PARAGRAPH.RIGHT\n    run = p.add_run(str(text or ''))\n    run.bold = bold\n    run.italic = italic\n    run.font.size = Pt(size)\n    run.font.color.rgb = hex_to_rgb(color)\n    if mono:\n        run.font.name = 'Courier New'\n        run._element.rPr.rFonts.set(qn('w:eastAsia'), 'Courier New')\n    return p\n\ndef add_heading(doc, text, level=1):\n    style = 'Heading ' + str(level)\n    try:\n        p = doc.add_paragraph(style=style)\n    except Exception:\n        p = doc.add_paragraph()\n    p.paragraph_format.space_before = Pt(10 if level == 1 else 6)\n    p.paragraph_format.space_after = Pt(6)\n    run = p.add_run(str(text or ''))\n    run.bold = True\n    run.font.size = Pt(15 if level == 1 else 12)\n    run.font.color.rgb = hex_to_rgb(DARK_BLUE if level == 1 else BRAND_BLUE)\n    return p\n\ndef add_preformatted(doc, text, limit=2500):\n    content = (text or '').strip() or 'Data tidak tersedia.'\n    content = content[:limit]\n    add_para(doc, content, mono=True, size=8, color=BLACK)\n\ndef replace_text_in_paragraph(paragraph, replacements):\n    if not paragraph.runs:\n        return\n    original = ''.join(run.text for run in paragraph.runs)\n    updated = original\n    for old, new in replacements.items():\n        updated = updated.replace(old, str(new))\n    if updated != original:\n        paragraph.runs[0].text = updated\n        for run in paragraph.runs[1:]:\n            run.text = ''\n\ndef replace_text_in_table(table, replacements):\n    for row in table.rows:\n        for cell in row.cells:\n            for p in cell.paragraphs:\n                replace_text_in_paragraph(p, replacements)\n            for nested in cell.tables:\n                replace_text_in_table(nested, replacements)\n\ndef replace_text_in_part(part, replacements):\n    for p in part.paragraphs:\n        replace_text_in_paragraph(p, replacements)\n    for table in part.tables:\n        replace_text_in_table(table, replacements)\n\ndef clear_doc_body(doc):\n    body = doc._body._element\n    for child in list(body):\n        if child.tag != qn('w:sectPr'):\n            body.remove(child)\n\ndef configure_doc_from_template(doc):\n    try:\n        normal = doc.styles['Normal']\n        normal.font.name = 'Calibri'\n        normal.font.size = Pt(10)\n    except Exception:\n        pass\n    replacements = {\n        '(tgl bulan pembuatan dokumen)': month_year,\n        '(tgl update)': today_fmt,\n        '(nama perusahaan client)': client_name,\n        'Support and Maintenance MariaDB': report_title,\n    }\n    for section in doc.sections:\n        section.different_first_page_header_footer = True\n        replace_text_in_part(section.header, replacements)\n        replace_text_in_part(section.footer, replacements)\n        replace_text_in_part(section.first_page_header, replacements)\n        replace_text_in_part(section.first_page_footer, replacements)\n\ndef add_template_logo(doc):\n    try:\n        with ZipFile(template_path) as z:\n            media = [name for name in z.namelist() if name.startswith('word/media/')]\n            if not media:\n                return\n            image_name = media[0]\n            ext = os.path.splitext(image_name)[1] or '.png'\n            image_path = '/tmp/pm_template_logo' + ext\n            with open(image_path, 'wb') as out:\n                out.write(z.read(image_name))\n            p = doc.add_paragraph()\n            p.alignment = WD_ALIGN_PARAGRAPH.CENTER\n            run = p.add_run()\n            run.add_picture(image_path, width=Cm(4.2))\n            doc.add_paragraph()\n    except Exception:\n        pass\n\ndef add_cover(doc):\n    add_template_logo(doc)\n    add_para(doc, 'Preventive Maintenance Report', bold=True, color=DARK_BLUE, size=24, align='center')\n    add_para(doc, report_title, bold=True, color=BRAND_BLUE, size=16, align='center')\n    add_para(doc, month_year, color=BLACK, size=12, align='center')\n    for _ in range(5):\n        doc.add_paragraph()\n    add_para(doc, 'Written for:', bold=True, size=10)\n    add_para(doc, client_name, size=10)\n    doc.add_paragraph()\n    add_para(doc, 'Last Update:', bold=True, size=10)\n    add_para(doc, today_fmt, size=10)\n    doc.add_paragraph()\n    add_para(doc, 'Prepared By:', bold=True, size=10)\n    add_para(doc, 'PT. Bajau Escorindo', bold=True, size=10)\n    add_para(doc, '18 Office Park, 22nd Floor, Suite E, F & G.', size=9)\n    add_para(doc, 'Jl. TB Simatupang Kav. 18, Jakarta Selatan 12520', size=9)\n    add_para(doc, 'Telp: +62 21 505 78999', size=9)\n    add_para(doc, 'Fax: +62 21 506 78999', size=9)\n    add_para(doc, 'www.bajau.com', color=BRAND_BLUE, size=9)\n    doc.add_page_break()\n\ndef add_front_matter(doc):\n    add_heading(doc, 'Confidentiality Statement', 1)\n    add_para(doc, 'The information in this document shall not be disclosed outside of ' + client_name + ' and shall not be duplicated, used, or disclosed in whole or in part for any purpose other than to evaluate this document.', size=9)\n    add_para(doc, 'PT. Bajau Escorindo may use general know-how developed during service delivery, provided that such information does not disclose confidential customer information.', size=9)\n    add_table(doc, ['Publication Detail', 'Description'], [\n        ['Purpose', 'This documentation is prepared as a Preventive Maintenance Report for ' + client_name + '.'],\n        ['Scope', 'This document covers collected system and MariaDB/PerconaDB data, observed conditions, findings, and recommendations.'],\n        ['Generated From', file_name],\n        ['Generated Date', today_fmt],\n        ['Collection Profile', collection_profile],\n        ['Missing Expected Files', missing_note],\n    ])\n    add_heading(doc, 'Contents', 1)\n    add_table(doc, ['Section', 'Title'], [\n        ['1', 'Introduction'],\n        ['2', 'Maintenance Checklist'],\n        ['3', 'Maintenance Summary'],\n        ['4', hostname + ' - Server Information'],\n        ['5', hostname + ' - DB CHECK'],\n        ['6', 'SYSTEM PERFORMANCE METRICS'],\n        ['7', 'MARIADB PERFORMANCE METRICS'],\n        ['8', 'REPLICATION / CLUSTER STATUS'],\n        ['9', 'Known Issues and Recommendations'],\n    ])\n    doc.add_page_break()\n\nglob_vars = parse_kv(sections.get('mariadb_glob_vars.txt', ''))\ncluster_kv = parse_kv(sections.get('cluster_integrity.txt', ''))\ngtid_kv = parse_kv(sections.get('gtid.txt', ''))\ncnf_text = '\\\\n'.join(sections[k] for k in sections if k.endswith('.cnf') or k.endswith('.conf') or k == 'mariadb.conf' or k == 'my.cnf')\ncnf_kv = parse_kv(cnf_text)\n\nslave_kv = {}\nfor line in sections.get('slave_status.txt', '').split('\\\\n'):\n    m = re.match(r'^\\\\s*([A-Za-z0-9_]+):\\\\s*(.*)$', line)\n    if m:\n        slave_kv[m.group(1)] = m.group(2).strip()\n\ndb_size_rows = []\nfor line in sections.get('db_size.txt', '').split('\\\\n'):\n    p = line.strip().split()\n    if len(p) >= 3 and p[0] not in ('Total_Table_Count', 'COUNT(*)') and not p[0].lower().startswith('schema'):\n        db_size_rows.append({'count': p[0], 'schema': p[1], 'size': p[2], 'gb': size_to_gb(p[2])})\nmax_size = max([r['gb'] for r in db_size_rows] + [1])\n\ntotal_tables = 0\ninno_tables = 0\nnon_inno = []\nknown_engines = {'INNODB', 'MYISAM', 'MEMORY', 'ARIA', 'CSV', 'PERFORMANCE_SCHEMA', 'BLACKHOLE', 'MRG_MYISAM', 'SEQUENCE', 'FEDERATED'}\nfor line in sections.get('table_engine.txt', '').split('\\\\n'):\n    p = line.strip().split()\n    if len(p) >= 2 and p[-1].upper() in known_engines and p[0].upper() not in ('TABLE_NAME', 'ENGINE'):\n        total_tables += 1\n        engine = p[-1]\n        table_name = ' '.join(p[:-1])\n        if engine.upper() == 'INNODB':\n            inno_tables += 1\n        else:\n            non_inno.append({'table': table_name, 'engine': engine})\n\nmariadb_ver = first_nonempty_line(sections.get('mariadb_version.txt', ''), 'N/A')\nbp_reads = safe_int(glob_vars.get('Innodb_buffer_pool_reads'), 0)\nbp_requests = safe_int(glob_vars.get('Innodb_buffer_pool_read_requests'), 1) or 1\nbp_ratio = round((bp_requests / max(bp_reads + bp_requests, 1)) * 100, 2)\nbp_ok = bp_ratio >= 99\nmax_conn = safe_int(cnf_kv.get('max_connections', glob_vars.get('max_connections')), 151) or 151\nthreads_conn = safe_int(glob_vars.get('Threads_connected'), 0)\nthreads_running = safe_int(glob_vars.get('Threads_running'), 0)\nconn_pct = round((threads_conn / max(max_conn, 1)) * 100, 1)\nslow_q = safe_int(glob_vars.get('Slow_queries'), 0)\nrow_lock = safe_int(glob_vars.get('Innodb_row_lock_waits'), 0)\nquestions = safe_int(glob_vars.get('Questions'), 0)\nqueries = safe_int(glob_vars.get('Queries'), 0)\n\nslave_io = slave_kv.get('Slave_IO_Running', 'N/A')\nslave_sql = slave_kv.get('Slave_SQL_Running', 'N/A')\nseconds_behind = safe_int(slave_kv.get('Seconds_Behind_Master'), 999999)\nhas_replication = bool(slave_kv)\nreplication_ok = (not has_replication) or (slave_io == 'Yes' and slave_sql == 'Yes' and seconds_behind <= 30)\nreplication_status = 'Synced' if has_replication and replication_ok else ('Attention' if has_replication else '-')\n\nwsrep_cluster_status = cluster_kv.get('wsrep_cluster_status', cluster_kv.get('wsrep_local_state_comment', '-'))\nwsrep_local_state = cluster_kv.get('wsrep_local_state_comment', '-')\nhas_cluster = any(k.lower().startswith('wsrep') for k in cluster_kv.keys())\ncluster_ok = (not has_cluster) or (str(wsrep_cluster_status).lower() == 'primary' or str(wsrep_local_state).lower() == 'synced')\ngalera_status = 'Synced' if has_cluster and cluster_ok else ('Attention' if has_cluster else '-')\nservice_status = 'Running' if mariadb_ver != 'N/A' or glob_vars else '-'\n\nsar_lines = [l for l in sections.get('sar.txt', '').split('\\\\n') if 'Average' in l or re.search(r'\\\\ball\\\\b', l)][-12:]\nsar_summary = '\\\\n'.join(sar_lines) or 'Data SAR tidak tersedia.'\ntuner_lines = [l.strip() for l in sections.get('mysql_tunner.txt', '').split('\\\\n') if re.search(r'\\\\[!!\\\\]|\\\\[OK\\\\]|\\\\[--\\\\]|recommend', l, re.I)][:30]\n\nsource_file_rows = []\nfor src_name in required_pm_files:\n    available = bool(sections.get(src_name))\n    source_file_rows.append([src_name, status_cell('Available' if available else 'Missing', available), 'Captured from PM archive' if available else 'Not found in archive'])\ncnf_present = any(k.endswith('.cnf') or k.endswith('.conf') or k == 'mariadb.conf' or k == 'my.cnf' for k in sections)\nsource_file_rows.append(['*.cnf / *.conf', status_cell('Available' if cnf_present else 'Missing', cnf_present), 'MariaDB configuration copied by PM script'])\nif sections.get('sosreport_warn.txt'):\n    source_file_rows.append(['sosreport_warn.txt', status_cell('Warning', False), sections.get('sosreport_warn.txt', '')[:180]])\nmissing_note = ', '.join(missing_files) if missing_files else 'All expected PM files are available.'\n\nai_clean = re.sub(r'[\\\\x00-\\\\x08\\\\x0B\\\\x0C\\\\x0E-\\\\x1F\\\\x7F]', '', ai_resp or '')\nai_clean = ai_clean.replace('<', '').replace('>', '').replace(chr(96), \"'\")\n\noverall_status = 'HEALTHY'\noverall_color = GREEN\nif not bp_ok or slow_q > 500000 or row_lock > 1000 or not replication_ok or not cluster_ok:\n    overall_status = 'WARNING'\n    overall_color = YELLOW\nif (not bp_ok and bp_ratio < 90) or (has_replication and not replication_ok) or (has_cluster and not cluster_ok):\n    overall_status = 'CRITICAL'\n    overall_color = RED\n\nissues = []\nif not bp_ok:\n    issues.append(['1', 'InnoDB Buffer Pool Hit Ratio di bawah target', 'Hit ratio ' + str(bp_ratio) + '%, target > 99%.', severity_cell('HIGH' if bp_ratio >= 90 else 'CRITICAL'), 'Review innodb_buffer_pool_size dan pola query.', hostname])\nif slow_q > 100000:\n    issues.append([str(len(issues)+1), 'Slow queries tinggi', 'Total Slow_queries: ' + str(slow_q), severity_cell('MEDIUM' if slow_q <= 500000 else 'HIGH'), 'Review slow log, index, dan query dengan waktu eksekusi tinggi.', hostname])\nif row_lock > 1000:\n    issues.append([str(len(issues)+1), 'Row lock waits tinggi', 'Innodb_row_lock_waits: ' + str(row_lock), severity_cell('HIGH'), 'Investigasi transaksi panjang dan query yang menahan lock.', hostname])\nif has_replication and not replication_ok:\n    issues.append([str(len(issues)+1), 'Replication health perlu perhatian', 'IO=' + slave_io + ', SQL=' + slave_sql + ', lag=' + str(slave_kv.get('Seconds_Behind_Master', 'N/A')), severity_cell('CRITICAL'), 'Periksa error replication dan sinkronisasi posisi binlog/GTID.', hostname])\nif has_cluster and not cluster_ok:\n    issues.append([str(len(issues)+1), 'Cluster status tidak normal', 'wsrep_cluster_status=' + str(wsrep_cluster_status) + ', state=' + str(wsrep_local_state), severity_cell('CRITICAL'), 'Validasi quorum, network antar node, dan state Galera.', hostname])\nif non_inno:\n    issues.append([str(len(issues)+1), 'Tabel non-InnoDB ditemukan', str(len(non_inno)) + ' tabel tidak memakai InnoDB.', severity_cell('LOW'), 'Evaluasi migrasi engine untuk konsistensi dan crash recovery.', hostname])\nif not issues:\n    issues.append(['1', 'Tidak ada issue kritis otomatis', 'Tidak ditemukan anomali utama dari rule generator.', severity_cell('LOW'), 'Tetap validasi manual pada data mentah dan rekomendasi AI.', hostname])\n\ntry:\n    doc = Document(template_path)\nexcept Exception as exc:\n    raise RuntimeError('Template DOCX tidak bisa dibuka: ' + template_path + ' - ' + str(exc))\n\nconfigure_doc_from_template(doc)\nclear_doc_body(doc)\n\nadd_cover(doc)\nadd_front_matter(doc)\n\nadd_heading(doc, 'Introduction', 1)\nadd_para(doc, 'This Preventive Maintenance Report summarizes the collected operating system and MariaDB/PerconaDB information for ' + hostname + '. The report follows the Bajau PM document format and includes service status, replication or cluster health, resource utilization, database indicators, known issues, and recommendations.', size=10)\n\nadd_heading(doc, 'PM Data Source Coverage', 2)\nadd_para(doc, 'Collection reference: ' + collection_profile + '. Expected files follow the attached PM MariaDB collection script.', size=9)\nadd_table(doc, ['Expected File', 'Status', 'Notes'], source_file_rows)\nif missing_files:\n    add_para(doc, 'Missing expected files: ' + missing_note + '. Values that depend on these files are reported as N/A.', size=9, color=RED)\n\nadd_heading(doc, 'Maintenance Checklist', 1)\nadd_table(doc, ['Category', 'Item', 'Status', 'Details'], [\n    ['PM Source Data', 'Reference s