const http = require('http');

// Helper request â€” pakai http builtin, bukan axios/fetch
function req(host, port, path, method, body, timeoutMs = 60000) {
  return new Promise((resolve, reject) => {
    const payload = body ? JSON.stringify(body) : null;
    const options = {
      hostname: host,
      port,
      path,
      method,
      headers: {
        'Content-Type': 'application/json',
        ...(payload ? { 'Content-Length': Buffer.byteLength(payload) } : {})
      }
    };
    const r = http.request(options, (res) => {
      const bufs = [];
      res.on('data', c => bufs.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(bufs).toString())); }
        catch(e) { resolve({}); }
      });
    });
    r.on('error', reject);
    r.setTimeout(timeoutMs, () => r.destroy(new Error('timeout')));
    if (payload) r.write(payload);
    r.end();
  });
}

