const serverName = (pmMeta.fileName || 'unknown').split('_')[0];

const CHUNK_SIZE  = 800;
const OVERLAP     = 80;
const BATCH_SIZE  = 3;          // â† lebih kecil lagi: 3 chunk per iterasi
const OLLAMA_HOST = '100.120.54.111';
const OLLAMA_PORT = 11434;
const QDRANT_HOST = 'qdrant';
const QDRANT_PORT = 6333;
const COLLECTION  = 'it_knowledge';

// Buat collection (idempotent)
try {
  await req(QDRANT_HOST, QDRANT_PORT,
    `/collections/${COLLECTION}`, 'PUT',
    { vectors: { size: 768, distance: 'Cosine' } }, 10000);
} catch(e) {}

// Chunking â€” batasi teks maks 12 000 char untuk keamanan
const safeText = text.slice(0, 12000);
const chunks   = [];
let i = 0;
while (i < safeText.length) {
  chunks.push(safeText.slice(i, i + CHUNK_SIZE));
  i += CHUNK_SIZE - OVERLAP;
}

const baseId  = Date.now();
let ingested  = 0;

for (let b = 0; b < chunks.length; b += BATCH_SIZE) {
  const batch = chunks.slice(b, b + BATCH_SIZE);

  // Embed batch
  const embedData = await req(OLLAMA_HOST, OLLAMA_PORT,
    '/api/embed', 'POST',
    { model: 'nomic-embed-text', input: batch }, 60000);

  const vectors = embedData.embeddings || [];
  if (!vectors.length) continue;

  // Upsert ke Qdrant
  const points = vectors.map((vector, idx) => ({
    id     : baseId + b + idx,
    vector,
    payload: {
      doc_type    : 'pm_document',
      server_name : serverName,
      file_name   : pmMeta.fileName || 'unknown',
      generated_at: new Date().toISOString(),
      chunk_index : b + idx,
      text        : batch[idx]
    }
  }));

  await req(QDRANT_HOST, QDRANT_PORT,
    `/collections/${COLLECTION}/points`, 'PUT',
    { points }, 30000);

  ingested += points.length;
}

return [{ json: { ingested_chunks: ingested, doc_type: 'pm_document', server: serverName } }];

