function normalizeMarkdownName(input) {
  const raw = String(input || '').trim();
  if (!raw) return '';
  if (/^\d+$/.test(raw)) {
    const files = listMarkdownReports();
    const index = Number(raw);
    if (index < 1 || index > files.length) {
      throw new Error('Nomor laporan tidak tersedia: ' + raw + '\nCek daftar terbaru: /gendoc');
    }
    return files[index - 1];
  }
  const mdName = raw.toLowerCase().endsWith('.md') ? raw : raw + '.md';
  if (/\s/.test(mdName) || /[\\/]/.test(mdName) || mdName.includes('..') || !/^[A-Za-z0-9._-]+\.md$/i.test(mdName)) {
    throw new Error('Nama file tidak valid: ' + raw + '\nGunakan nomor dari /gendoc atau nama file Markdown dari daftar /gendoc.');
  }
  return mdName;
}

function clean(value, maxLen) {
  const text = String(value ?? '')
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
    .replace(/\r/g, '')
    .replace(/\t/g, '    ')
    .trim();
  return maxLen && text.length > maxLen ? text.slice(0, maxLen) + '\n...[dipotong agar aman untuk dokumen]...' : text;
}

function htmlEscape(value) {
  return clean(value).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function mdEscapeCell(value) {
  return clean(value, 500).replace(/\|/g, '\\|').replace(/\n+/g, '<br>');
}

function parseKv(text) {
  const out = {};
  for (const line of String(text || '').split('\n')) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    let match = trimmed.match(/^([A-Za-z0-9_.$-]+)\s*[:=]\s*(.+)$/);
    if (!match) {
      const parts = trimmed.split(/\s+/);
      if (parts.length >= 2) match = [trimmed, parts[0], parts.slice(1).join(' ')];
    }
    if (match) out[match[1]] = match[2];
  }
  return out;
}

function parseSlave(text) {
  const out = {};
  for (const line of String(text || '').split('\n')) {
    const match = line.match(/^\s*([A-Za-z0-9_]+):\s*(.*)$/);
    if (match) out[match[1]] = match[2].trim();
  }
  return out;
}

function asInt(value, fallback) {
  const n = Number(String(value ?? '').replace(/[^0-9.-]/g, ''));
  return Number.isFinite(n) ? n : fallback;
}

function mdTable(headers, rows) {
  const head = '| ' + headers.map(mdEscapeCell).join(' | ') + ' |';
  const sep = '| ' + headers.map(() => '---').join(' | ') + ' |';
  const body = rows.map((row) => '| ' + row.map(mdEscapeCell).join(' | ') + ' |');
  return [head, sep, ...body].join('\n');
}

function htmlTable(headers, rows) {
  const head = '<thead><tr>' + headers.map((h) => '<th>' + htmlEscape(h) + '</th>').join('') + '</tr></thead>';
  const body = '<tbody>' + rows.map((row) => '<tr>' + row.map((c) => '<td>' + htmlEscape(c).replace(/\n/g, '<br>') + '</td>').join('') + '</tr>').join('') + '</tbody>';
  return '<table>' + head + body + '</table>';
}

function mdPre(text) {
  const fence = String.fromCharCode(96).repeat(3);
  return fence + 'text\n' + clean(text || 'N/A', 8000).replace(new RegExp(fence, 'g'), "'''") + '\n' + fence;
}

function htmlPre(text) {
