}

function formatDateId(isoDate) {
  const monthNames = ['Januari','Februari','Maret','April','Mei','Juni','Juli','Agustus','September','Oktober','November','Desember'];
  const d = new Date(String(isoDate || '').slice(0, 10) + 'T00:00:00');
  if (Number.isNaN(d.getTime())) return isoDate;
  return String(d.getDate()).padStart(2, '0') + ' ' + monthNames[d.getMonth()] + ' ' + d.getFullYear();
}

function tableValue(markdown, key) {
  const target = String(key).toLowerCase();
  for (const line of String(markdown || '').split('\n')) {
    if (!line.trim().startsWith('|')) continue;
    const cells = line.split('|').slice(1, -1).map((part) => part.trim());
    if (cells.length >= 2 && cells[0].toLowerCase() === target) {
      return cells[1].replace(/<br>/g, '\n').trim();
    }
  }
  return '';
}

