function sendDocument(tkn, cid, targetPath, caption, contentType) {
  return new Promise((resolve, reject) => {
    const boundary = 'X' + Math.random().toString(36).slice(2) + Date.now();
    const uploadName = path.basename(targetPath);
    const fileData = fs.readFileSync(targetPath);
    const CRLF = '\r\n';
    const enc = (s) => Buffer.from(s, 'utf8');
    const body = Buffer.concat([
      enc('--' + boundary + CRLF),
      enc('Content-Disposition: form-data; name="chat_id"' + CRLF + CRLF),
      enc(cid + CRLF),
      enc('--' + boundary + CRLF),
      enc('Content-Disposition: form-data; name="caption"' + CRLF + CRLF),
      enc(caption + CRLF),
      enc('--' + boundary + CRLF),
      enc('Content-Disposition: form-data; name="document"; filename="' + uploadName + '"' + CRLF),
      enc('Content-Type: ' + contentType + CRLF + CRLF),
      fileData,
      enc(CRLF + '--' + boundary + '--' + CRLF),
    ]);
    const req = https.request({
      hostname: 'api.telegram.org',
      port: 443,
      path: '/bot' + tkn + '/sendDocument',
      method: 'POST',
      headers: { 'Content-Type': 'multipart/form-data; boundary=' + boundary, 'Content-Length': body.length }
    }, (res) => {
      const chunks = [];
      res.on('data', (c) => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch (e) { resolve({ ok: false, description: 'Invalid Telegram response' }); }
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

function sendMessage(tkn, cid, message) {
  return new Promise((resolve, reject) => {
    const body = Buffer.from(JSON.stringify({ chat_id: cid, text: message }), 'utf8');
    const req = https.request({
      hostname: 'api.telegram.org',
      port: 443,
      path: '/bot' + tkn + '/sendMessage',
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': body.length }
    }, (res) => {
      const chunks = [];
      res.on('data', (c) => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch (e) { resolve({}); }
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

