function detectType(text) {
  const htmlPattern = /<\s*([a-z0-9]+)(\s+[^>]*)?>.*?<\s*\/\1>/is;
  const htmlSelfClosing = /<\s*([a-z0-9]+)(\s+[^>]*)?\/>/i;
  const markdownPatterns = [
    /^\s{0,3}#/m,
    /\*\*.*\*\*/, /__.*__/,
    /\*[^*]+\*/, /_[^_]+_/,
    /\[[^\]]+\]\([^)]+\)/,
    /^\s{0,3}- /m, /^\s{0,3}\* /m,
    /^\s*\|.+\|\s*$/m,
    /\x60\x60\x60[\s\S]*?\x60\x60\x60/,
    /^\s{4,}/m
  ];

  if (htmlPattern.test(text) || htmlSelfClosing.test(text)) {
    return { type: 'html', confidence: 0.98 };
  }

  let markdownMatches = 0;
  markdownPatterns.forEach((re) => {
    if (re.test(text)) markdownMatches++;
  });

  if (markdownMatches > 1) {
    return { type: 'markdown', confidence: 0.95 + 0.01 * markdownMatches };
  }

  return { type: 'plain_text', confidence: 0.80 };
}

