function replaceMarkedBlock(html, marker, replacement) {
  const startToken = '<!-- ' + marker + '_START -->';
  const endToken = '<!-- ' + marker + '_END -->';
  const start = html.indexOf(startToken);
  const end = html.indexOf(endToken);
  if (start < 0 || end < 0 || end <= start) return html;
  return html.slice(0, start + startToken.length) + replacement + html.slice(end);
}

