  return '<div class="metric-caption">Avg ' + htmlEscape(String(stats.avg ?? 'N/A') + unit) + ' | Max ' + htmlEscape(String(stats.max ?? 'N/A') + unit) + ' | Period ' + htmlEscape(stats.period || '30 hari terakhir / data timestamp tidak tersedia') + '</div>';
}

