  fs.writeFileSync(scriptPath, "
import base64
import io
import json
import math
import struct
import sys
import zlib

try:
    import matplotlib
    matplotlib.use("Agg")
    import matplotlib.pyplot as plt
    HAS_MATPLOTLIB = True
except Exception:
    HAS_MATPLOTLIB = False


def as_float(value):
    try:
        number = float(value)
    except Exception:
        return None
    if not math.isfinite(number):
        return None
    return number


def parse_points(chart):
    points = chart.get("points") or []
    labels = []
    values = []
    for idx, point in enumerate(points):
        value = as_float(point.get("value"))
        if value is None:
            continue
        label = str(point.get("label") or point.get("day") or point.get("time") or idx + 1)
        labels.append(label)
        values.append(value)
    return labels, values


def chart_stats(chart, values):
    raw_points = chart.get("raw_points") or len(values)
    return {
        "min": round(min(values), 2),
        "max": round(max(values), 2),
        "avg": round(sum(values) / len(values), 2),
        "points": len(values),
        "rawPoints": int(raw_points) if str(raw_points).isdigit() else raw_points,
        "period": chart.get("period") or "30 hari terakhir / data timestamp tidak tersedia",
    }


def render_matplotlib(chart, labels, values):
    title = str(chart.get("title") or "Metric")
    unit = str(chart.get("unit") or "")
    x_values = list(range(len(values)))

    fig, ax = plt.subplots(figsize=(6.4, 2.35), dpi=150)
    ax.fill_between(x_values, values, color="#8ee5ef", alpha=0.80, linewidth=0)
    ax.plot(x_values, values, color="#08bcd4", linewidth=1.8)
    ax.scatter(x_values, values, s=18, color="#08bcd4", edgecolors="#ffffff", linewidths=1.1, zorder=3)

    max_value = max(values)
    y_top = max(100, int(math.ceil(max_value / 10.0) * 10)) if max_value > 0 else 100
    ax.set_ylim(0, y_top)
    ax.set_title(title, fontsize=10, color="#374151", loc="left", pad=7)
    ax.set_ylabel(unit, fontsize=8, color="#475569")
    ax.grid(True, axis="y", color="#e5e7eb", linewidth=0.8)
    ax.grid(False, axis="x")
    ax.spines["top"].set_visible(False)
    ax.spines["right"].set_visible(False)
    ax.spines["left"].set_color("#d8e1ea")
    ax.spines["bottom"].set_color("#d8e1ea")
    ax.tick_params(axis="both", labelsize=7, colors="#475569")

    if len(x_values) == 1:
        tick_positions = [0]
    else:
        step = max(1, int(math.ceil(len(x_values) / 7.0)))
        tick_positions = list(range(0, len(x_values), step))
        if tick_positions[-1] != len(x_values) - 1:
            tick_positions.append(len(x_values) - 1)
    ax.set_xticks(tick_positions)
    ax.set_xticklabels([labels[pos] for pos in tick_positions], rotation=0, ha="center")

    fig.tight_layout()
    buffer = io.BytesIO()
    fig.savefig(buffer, format="png", bbox_inches="tight", facecolor="white")
    plt.close(fig)
    return buffer.getvalue()


def blend_pixel(pixels, width, height, x, y, color, alpha=1.0):
    x = int(round(x))
    y = int(round(y))
    if x < 0 or y < 0 or x >= width or y >= height:
        return
    idx = (y * width + x) * 3
    if alpha >= 1:
        pixels[idx:idx + 3] = bytes(color)
        return
    inv = 1.0 - alpha
    pixels[idx] = int(pixels[idx] * inv + color[0] * alpha)
    pixels[idx + 1] = int(pixels[idx + 1] * inv + color[1] * alpha)
    pixels[idx + 2] = int(pixels[idx + 2] * inv + color[2] * alpha)


def draw_hline(pixels, width, height, y, x1, x2, color, alpha=1.0):
    y = int(round(y))
    if y < 0 or y >= height:
        return
    start = max(0, int(round(min(x1, x2))))
    end = min(width - 1, int(round(max(x1, x2))))
    for x in range(start, end + 1):
        blend_pixel(pixels, width, height, x, y, color, alpha)


def draw_vline(pixels, width, height, x, y1, y2, color, alpha=1.0):
    x = int(round(x))
    if x < 0 or x >= width:
        return
    start = max(0, int(round(min(y1, y2))))
    end = min(height - 1, int(round(max(y1, y2))))
    for y in range(start, end + 1):
        blend_pixel(pixels, width, height, x, y, color, alpha)


def draw_circle(pixels, width, height, cx, cy, radius, color, alpha=1.0):
    radius = int(radius)
    cx = int(round(cx))
    cy = int(round(cy))
    rr = radius * radius
    for y in range(cy - radius, cy + radius + 1):
        for x in range(cx - radius, cx + radius + 1):
            if (x - cx) * (x - cx) + (y - cy) * (y - cy) <= rr:
                blend_pixel(pixels, width, height, x, y, color, alpha)


def draw_line(pixels, width, height, x1, y1, x2, y2, color, thickness=2):
    steps = int(max(abs(x2 - x1), abs(y2 - y1), 1))
    radius = max(1, int(math.ceil(thickness / 2.0)))
    for step in range(steps + 1):
        ratio = step / steps
        x = x1 + (x2 - x1) * ratio
        y = y1 + (y2 - y1) * ratio
        draw_circle(pixels, width, height, x, y, radius, color, 1.0)


def fill_area(pixels, width, height, points, baseline, color, alpha=0.80):
    if not points:
        return
    if len(points) == 1:
        x, y = points[0]
        for yy in range(int(round(y)), int(round(baseline)) + 1):
            draw_hline(pixels, width, height, yy, x - 2, x + 2, color, alpha)
        return
    for idx in range(len(points) - 1):
        x1, y1 = points[idx]
        x2, y2 = points[idx + 1]
        if x2 < x1:
            x1, y1, x2, y2 = x2, y2, x1, y1
        start = int(round(x1))
        end = int(round(x2))
        span = max(x2 - x1, 1.0)
        for x in range(start, end + 1):
            ratio = (x - x1) / span
            y = y1 + (y2 - y1) * ratio
            draw_vline(pixels, width, height, x, y, baseline, color, alpha)


def png_bytes(width, height, pixels):
    def chunk(kind, data):
        return struct.pack(">I", len(data)) + kind + data + struct.pack(">I", zlib.crc32(kind + data) & 0xffffffff)

    raw = bytearray()
    stride = width * 3
    for y in range(height):
        raw.append(0)
        start = y * stride
        raw.extend(pixels[start:start + stride])
    return (
        b"\x89PNG\r\n\x1a\n" +
        chunk(b"IHDR", struct.pack(">IIBBBBB", width, height, 8, 2, 0, 0, 0)) +
        chunk(b"IDAT", zlib.compress(bytes(raw), 9)) +
        chunk(b"IEND", b"")
    )


def render_stdlib(chart, labels, values):
    width = 760
    height = 280
    left = 48
    right = 18
    top = 32
    bottom = 34
    chart_w = width - left - right
    chart_h = height - top - bottom
    baseline = top + chart_h
    max_value = max(values)
    y_top = max(100, int(math.ceil(max_value / 10.0) * 10)) if max_value > 0 else 100
    pixels = bytearray([255, 255, 255]) * (width * height)

    grid_color = (229, 231, 235)
    axis_color = (216, 225, 234)
    fill_color = (142, 229, 239)
    line_color = (8, 188, 212)
    white = (255, 255, 255)

    for ratio in [0, 0.25, 0.5, 0.75, 1]:
        y = baseline - ratio * chart_h
        draw_hline(pixels, width, height, y, left, width - right, grid_color, 1.0)
    draw_vline(pixels, width, height, left, top, baseline, axis_color, 1.0)
    draw_hline(pixels, width, height, baseline, left, width - right, axis_color, 1.0)

    coords = []
    for idx, value in enumerate(values):
        x = left + (chart_w / 2 if len(values) == 1 else (idx / (len(values) - 1)) * chart_w)
        y = baseline - (value / y_top) * chart_h
        coords.append((x, y))

    fill_area(pixels, width, height, coords, baseline, fill_color, 0.80)
    for idx in range(len(coords) - 1):
        x1, y1 = coords[idx]
        x2, y2 = coords[idx + 1]
        draw_line(pixels, width, height, x1, y1, x2, y2, line_color, 3)
    for x, y in coords:
        draw_circle(pixels, width, height, x, y, 5, white, 1.0)
        draw_circle(pixels, width, height, x, y, 3, line_color, 1.0)

    return png_bytes(width, height, pixels)


def chart_result(chart):
    labels, values = parse_points(chart)

    if not values:
        return None

    renderer = "python_stdlib"
    try:
        if HAS_MATPLOTLIB:
            image = render_matplotlib(chart, labels, values)
            renderer = "matplotlib"
        else:
            image = render_stdlib(chart, labels, values)
    except Exception:
        image = render_stdlib(chart, labels, values)
        renderer = "python_stdlib"

    return {
        "data_uri": "data:image/png;base64," + base64.b64encode(image).decode("ascii"),
        "stats": chart_stats(chart, values),
        "renderer": renderer,
    }


def main():
    with open(sys.argv[1], "r", encoding="utf-8") as handle:
        payload = json.load(handle)
    output = {}
    for chart in payload.get("charts", []):
        key = chart.get("key")
        if not key:
            continue
        output[key] = chart_result(chart)
    print(json.dumps(output))


if __name__ == "__main__":
    main()
